import acm.program.*;
import acm.graphics.*;
import java.awt.event.*;
import javax.swing.*;

public class ButtonCounter extends GraphicsProgram {
    private int counter = 0;
    private GLabel display;

    public void init() {
        add(new JButton("Count"), SOUTH);
        addActionListeners();
        display = new GLabel("0", 20, 40);
        add(display);
    }

    public void actionPerformed(ActionEvent e) {
        if (e.getActionCommand().equals("Count")) {
            counter++;
            display.setLabel(Integer.toString(counter));
        }
    }
}

import acm.program.*;
import acm.graphics.*;
import java.awt.event.*;

public class DragDemo extends GraphicsProgram {
    private GObject selected;
    private double dx, dy;

    public void run() {
        GOval ball = new GOval(50, 50, 60, 60);
        ball.setFilled(true);
        add(ball);
        addMouseListeners();
    }

    public void mousePressed(MouseEvent e) {
        selected = getElementAt(e.getX(), e.getY());
        if (selected != null) {
            dx = e.getX() - selected.getX();
            dy = e.getY() - selected.getY();
        }
    }

    public void mouseDragged(MouseEvent e) {
        if (selected != null) {
            selected.setLocation(e.getX() - dx, e.getY() - dy);
        }
    }

    public void mouseReleased(MouseEvent e) {
        selected = null;
    }
}

import acm.program.*;
import acm.graphics.*;
import java.awt.event.*;
import javax.swing.*;

public class TimerBounce extends GraphicsProgram {
    private GRect box;
    private JButton startBtn, stopBtn;
    private Timer timer;
    private double vx = 3, vy = 2;

    public void init() {
        box = new GRect(20, 20, 40, 40);
        box.setFilled(true);
        add(box);
        startBtn = new JButton("Start");
        stopBtn = new JButton("Stop");
        add(startBtn, SOUTH);
        add(stopBtn, SOUTH);
        addActionListeners();
        timer = new Timer(20, this);
    }

    public void actionPerformed(ActionEvent e) {
        Object src = e.getSource();
        if (src == startBtn) {
            timer.start();
        } else if (src == stopBtn) {
            timer.stop();
        } else if (src == timer) {
            step();
        }
    }

    private void step() {
        box.move(vx, vy);
        if (box.getX() < 0 || box.getX() + box.getWidth() > getWidth()) {
            vx = -vx;
        }
        if (box.getY() < 0 || box.getY() + box.getHeight() > getHeight()) {
            vy = -vy;
        }
    }
}
